// logHTTP wraps any handler and logs incoming HTTP requests + responses
// with kubectl-style progressive verbosity:
//
//	v >= 1:  access log — method, URI, status, duration
//	v >= 4:  + request header names
//	v >= 8:  + full request header values (Authorization/Cookie redacted) + body length
//	v >= 10: + request body content (first 2048 bytes)
func logHTTP(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		v := mcputils.GetVerbosity()

		// Extract session ID for logging and pass it downstream via context
		sessionID := r.Header.Get("Mcp-Session-Id")
		ctx := mcputils.WithSessionID(r.Context(), sessionID)
		r = r.WithContext(ctx)

		sid := sessionID
		if sid == "" {
			sid = "-"
		}

		// Log request progressively
		if v >= 4 {
			reqLog := fmt.Sprintf("%s [http] sid=%s --> %s %s", start.Format(time.RFC3339), sid, r.Method, r.URL.RequestURI())
			reqLog += fmt.Sprintf(" headers=%s", mcputils.HTTPHeaderNames(r.Header))
			fmt.Fprintln(os.Stderr, reqLog)
		}
		if v >= 8 {
			for key, values := range r.Header {
				for _, val := range values {
					display := val
					if mcputils.IsSensitiveHeader(key) {
						display = "***"
					}
					fmt.Fprintf(os.Stderr, "%s [http] sid=%s    req %s: %s\n", start.Format(time.RFC3339), sid, key, display)
				}
			}
		}
		// v>=8: body length; v>=10: body content
		if v >= 8 && r.Body != nil && r.ContentLength > 0 {
			fmt.Fprintf(os.Stderr, "%s [http] sid=%s    req body: %d bytes\n", start.Format(time.RFC3339), sid, r.ContentLength)
		}
		if v >= 10 && r.Body != nil {
			bodyBytes, _ := io.ReadAll(r.Body)
			r.Body = io.NopCloser(strings.NewReader(string(bodyBytes)))
			fmt.Fprintf(os.Stderr, "%s [http] sid=%s    req body (%d bytes): %s\n", start.Format(time.RFC3339), sid, len(bodyBytes), truncate(string(bodyBytes), 2048))
		}

		lw := &loggingWriter{ResponseWriter: w, status: http.StatusOK}
		next.ServeHTTP(lw, r)

		// Log response
		if v >= 1 {
			fmt.Fprintf(os.Stderr, "%s [http] sid=%s <-- %d %s %s (%s)\n", time.Now().Format(time.RFC3339), sid, lw.status, r.Method, r.URL.RequestURI(), time.Since(start).Round(time.Millisecond))
		}
	})
}

type loggingWriter struct {
	http.ResponseWriter
	status int
}

func (l *loggingWriter) WriteHeader(code int) {
	l.status = code
	l.ResponseWriter.WriteHeader(code)
}

// Flush implements http.Flusher by delegating to the underlying ResponseWriter.
func (l *loggingWriter) Flush() {
	if f, ok := l.ResponseWriter.(http.Flusher); ok {
		f.Flush()
	}
}

func truncate(s string, max int) string {
	if len(s) > max {
		return s[:max] + "..."
	}
	if s == "" {
		return "(empty)"
	}
	return s
}

func usage() {
	fmt.Fprintf(os.Stderr, `sonarqube-mcp — Enterprise-grade MCP server generated by MCPfather (https://github.com/flowgent-labs/mcpfather).

Usage: sonarqube-mcp [OPTIONS] [TOOL_NAME] [JSON_ARGS]

Options:
  -t, --transport <stdio|http|cli>  Transport mode (default "stdio")
                                     cli mode: invoke a tool directly from the command line
  -p, --port <number>                HTTP server port (default 8080)
  --metrics-port <number>           Override mgmt.port from config.yaml (0: use config)
  -v, --verbose <0-10>              Request logging verbosity (kubectl-style progressive)
                                      0=silent, 1-3=status+duration, 4-7=+headers(names),
                                      8-9=+headers(values)+body(len), 10=+body(content)
  --print-default-config             Print default config.yaml to stdout and exit
  -h, --help                        Show this help message

CLI Mode:
  sonarqube-mcp -t cli list                   List all available tools
  sonarqube-mcp -t cli <tool-name> [OPTIONS]   Invoke a tool with GNU-style options
                                                   Use --help for tool-specific help
`)
}

