func main() {
	flag.CommandLine.SetOutput(os.Stderr)
	flag.Usage = usage

	transport := flag.String("t", "stdio", "Transport mode: stdio, http, or cli")
	flag.StringVar(transport, "transport", "stdio", "Transport mode: stdio, http, or cli")
	port := flag.Int("p", 8080, "HTTP server port (only used when transport=http)")
	flag.IntVar(port, "port", 8080, "HTTP server port (only used when transport=http)")
	metricsPort := flag.Int("metrics-port", 0, "Override mgmt.port from config.yaml (0: use config)")
	verbose := flag.Int("v", 0, "Request logging verbosity level (0-10)")
	flag.IntVar(verbose, "verbose", 0, "Request logging verbosity level (0-10)")
	printDefaultConfig := flag.Bool("print-default-config", false, "Print default config.yaml to stdout and exit")
	flag.Parse()

	if *printDefaultConfig {
		printDefaultConfigYAML()
		return
	}

	// Load config from $HOME/.{binaryName}/config.yaml with MCP__ env overrides
	cfg, err := mcputils.LoadConfig("sonarqube-mcp")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Warning: config load failed: %v\n", err)
	}
	if cfg == nil {
		cfg = &mcputils.Config{}
	}
	mcputils.SetConfig(cfg)

	// Initialize backend (outbound) credential managers (no-op if disabled)
	mcputils.InitOIDC(cfg.Auth.Backend.OIDC)
	defer mcputils.ShutdownOIDC()

	mcputils.SetVerbosity(*verbose)

	upstreamEndpoint := mcputils.GetUpstreamEndpoint()
	isDefault := mcputils.IsDefaultUpstreamEndpoint()

	fmt.Fprintf(os.Stderr, "Upstream endpoint: %s\n", upstreamEndpoint)
	if isDefault {
		fmt.Fprintln(os.Stderr, "Warning: upstream endpoint not configured. Using default (httpbin.org/anything) which echoes requests. Set upstream.endpoint in config.yaml or MCP__UPSTREAM__ENDPOINT env var.")
	}

	// Initialize management endpoints (metrics, tracing)
	mcputils.InitMetrics(cfg.Mgmt.Metrics)
	mcputils.InitTracing(cfg.Mgmt.Otel)
	defer func() {
		if err := mcputils.ShutdownTracing(context.Background()); err != nil {
			fmt.Fprintf(os.Stderr, "tracing shutdown error: %v\n", err)
		}
	}()

	switch *transport {
	case "cli":
		if flag.NArg() == 0 {
			fmt.Fprintf(os.Stderr, "Usage: %s -t cli <tool-name> [OPTIONS]\n", os.Args[0])
			fmt.Fprintf(os.Stderr, "       %s -t cli list\n", os.Args[0])
			fmt.Fprintf(os.Stderr, "\nUse -t cli <tool-name> --help for tool-specific help.\n")
			os.Exit(1)
		}
		subcmd := flag.Arg(0)
		switch subcmd {
		case "list":
			mcpcli.ListTools()
		default:
			if subcmd == "--help" || subcmd == "-h" {
				fmt.Fprintf(os.Stderr, "Usage: %s -t cli <tool-name> [OPTIONS]\n", os.Args[0])
				fmt.Fprintf(os.Stderr, "       %s -t cli list\n", os.Args[0])
				fmt.Fprintf(os.Stderr, "\nUse -t cli <tool-name> --help for tool-specific help.\n")
				os.Exit(0)
			}
			toolName := subcmd
			args := flag.Args()[1:]
			if err := mcpcli.Call(os.Args[0], toolName, args); err != nil {
				fmt.Fprintf(os.Stderr, "error: %v\n", err)
				os.Exit(1)
			}
		}

	case "http":
		s, err := mcpserver.NewMCPServer()
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error: %v\n", err)
			os.Exit(1)
		}

		mcpServer := server.NewStreamableHTTPServer(s,
			server.WithHTTPContextFunc(func(ctx context.Context, r *http.Request) context.Context {
				return mcputils.WithHTTPHeaders(ctx, r.Header)
			}),
		)

		ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
		defer cancel()

		mux := http.NewServeMux()

		// Frontend (inbound) auth: validate MCP client bearer tokens per the
		// MCP Authorization spec (2025-06-18) and RFC 9728. Only wired up for
		// the http transport — stdio has no network boundary to protect.
		var mcpHandler http.Handler = mcpServer
		if cfg.Auth.Frontend.OIDC.Enabled {
			if err := mcputils.InitFrontendAuth(ctx, cfg.Auth.Frontend.OIDC); err != nil {
				fmt.Fprintf(os.Stderr, "Error: frontend auth init failed: %v\n", err)
				os.Exit(1)
			}
			resource := mcputils.FrontendResource()
			metadataPath := server.ProtectedResourceMetadataPath(resource)
			mux.Handle(metadataPath, server.NewProtectedResourceMetadataHandler(server.ProtectedResourceMetadataConfig{
				Resource:               resource,
				AuthorizationServers:   []string{mcputils.FrontendIssuer()},
				BearerMethodsSupported: []string{"header"},
			}))
			mcpHandler = mcputils.RequireBearerToken(mcputils.ResourceMetadataURL(resource, metadataPath), mcpServer)
			fmt.Fprintf(os.Stderr, "Frontend auth enabled: issuer=%s resource=%s metadata=%s\n", mcputils.FrontendIssuer(), resource, metadataPath)
		}
		mux.Handle("/mcp", mcpHandler)

		addr := fmt.Sprintf(":%d", *port)
		httpServer := &http.Server{Addr: addr, Handler: logHTTP(mux)}

		go func() {
			fmt.Fprintf(os.Stderr, "MCP server listening on %s/mcp\n", addr)
			if err := httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				fmt.Fprintf(os.Stderr, "HTTP server error: %v\n", err)
				os.Exit(1)
			}
		}()

		// Management server (metrics, health)
		mgmtCfg := cfg.Mgmt
		var mgmtServer *http.Server
		if mgmtCfg.IsEnabled() {
			if *metricsPort > 0 {
				mgmtCfg.Port = *metricsPort
			}
			mgmtMux := http.NewServeMux()
			if h := mcputils.MetricsHandler(); h != nil {
				mgmtMux.Handle("/metrics", h)
			}
			mgmtMux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
				w.WriteHeader(http.StatusOK)
				w.Write([]byte("ok"))
			})
			mgmtAddr := fmt.Sprintf("%s:%d", mgmtCfg.Host, mgmtCfg.Port)
			mgmtServer = &http.Server{Addr: mgmtAddr, Handler: mgmtMux}

			go func() {
				fmt.Fprintf(os.Stderr, "Management server listening on %s\n", mgmtAddr)
				if err := mgmtServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
					fmt.Fprintf(os.Stderr, "Management server error: %v\n", err)
				}
			}()
		}

		// pprof server
		var pprofServer *http.Server
		if mgmtCfg.Pprof.Enabled {
			pprofServer = &http.Server{Addr: mgmtCfg.Pprof.ServerBind, Handler: nil}
			go func() {
				fmt.Fprintf(os.Stderr, "pprof server listening on %s\n", mgmtCfg.Pprof.ServerBind)
				if err := pprofServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
					fmt.Fprintf(os.Stderr, "pprof server error: %v\n", err)
				}
			}()
		}

		<-ctx.Done()
		fmt.Fprintln(os.Stderr, "Shutting down...")

		// Give in-flight requests a brief grace period, then force-close.
		// SSE streaming connections (GET /mcp) never become idle, so
		// Shutdown() alone would block forever waiting for them to drain.
		shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer shutdownCancel()
		if err := httpServer.Shutdown(shutdownCtx); err != nil {
			httpServer.Close()
		}
		if mgmtServer != nil {
			if err := mgmtServer.Shutdown(shutdownCtx); err != nil {
				mgmtServer.Close()
			}
		}
		if pprofServer != nil {
			if err := pprofServer.Shutdown(shutdownCtx); err != nil {
				pprofServer.Close()
			}
		}

	case "stdio":
		if cfg.Auth.Frontend.OIDC.Enabled {
			fmt.Fprintln(os.Stderr, "Warning: auth.frontend.oidc is enabled but ignored under stdio transport (no network boundary to protect; the parent process already controls access to stdin/stdout).")
		}

		s, err := mcpserver.NewMCPServer()
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error: %v\n", err)
			os.Exit(1)
		}

		if err := server.ServeStdio(s); err != nil {
			fmt.Fprintf(os.Stderr, "server error: %v\n", err)
			os.Exit(1)
		}

	default:
		fmt.Fprintf(os.Stderr, "unknown transport: %s (use 'stdio', 'http', or 'cli')\n", *transport)
		os.Exit(1)
	}
}
